"""
eval_ragas.py
=============
Direct Groq‑based RAGAS‑style evaluation (faithfulness,
answer_relevancy, context_recall, context_precision).
* Reads the original `phase_progress_<phase>.json` generated by the RAG pipeline.
* Writes **evaluated** results to a *new* file:
      phase_progress_<phase>_evaluated.json
  (the original file is never touched).
* If the evaluated file already exists, the script loads it and skips any entry
  that already has a `"scores"` key, allowing you to stop/re‑start safely.
* Handles Groq’s loop‑detection safety filter by appending/removing the
  “[ignoring loop detection]” tag automatically.
"""
import os
import json
import time
import re
from datetime import datetime
from openai import OpenAI
from dotenv import load_dotenv
from phase_eval_common import summarize_results, write_outputs
# ----------------------------------------------------------------------
# ── Configuration
# ----------------------------------------------------------------------
load_dotenv()
GROQ_API_KEY = os.getenv("GROQ_API_KEY")
if not GROQ_API_KEY:
    raise RuntimeError("GROQ_API_KEY not found in .env")
# Evaluator models – none overlap with the generator stack used in ask.py
EVALUATOR_MODELS = [
    "openai/gpt-oss-20b",
    "openai/gpt-oss-120b",
    "llama-3.1-8b-instant",
    "llama-3.3-70b-versatile",
    "qwen/qwen3-32b",
]
PHASES = ["simple", "medium", "complex"]
# Groq client (OpenAI‑compatible)
client = OpenAI(
    api_key=GROQ_API_KEY,
    base_url="https://api.groq.com/openai/v1",
)
_active_model = None          # cached evaluator model
_MAX_RETRIES = 4
_RATE_LIMIT_WAIT = 30         # seconds * attempt number
# ----------------------------------------------------------------------
# ── Helper: pick a working model (deep pre‑flight)
# ----------------------------------------------------------------------
def pick_working_model() -> str:
    """Return the first model that answers a tiny sanity‑check prompt."""
    global _active_model
    if _active_model:
        return _active_model
    sanity_prompt = "Respond ONLY with the word OK."
    for model in EVALUATOR_MODELS:
        try:
            resp = client.chat.completions.create(
                model=model,
                messages=[{"role": "user", "content": sanity_prompt}],
                max_tokens=5,
                temperature=0,
            )
            reply = resp.choices[0].message.content.strip().lower()
            if "ok" in reply:
                print(f"[OK] Using model: {model}")
                _active_model = model
                return model
        except Exception as e:
            print(f"[X] {model}: {e}")
    raise RuntimeError("No usable Groq evaluator model found.")
# ----------------------------------------------------------------------
# ── Prompt building (question, answer, contexts, ground truth + metrics)
# ----------------------------------------------------------------------
_FAITHFULNESS_PROMPT = (
    "Rate the FAITHFULNESS of the Answer with respect to the Context. "
    "Respond ONLY with a JSON object in this exact format: "
    '{"faithfulness": <float>, "reason": "<short‑explanation>"}.'
)
_ANSWER_RELEVANCY_PROMPT = (
    "Rate the RELEVANCY of the Answer to the Question. "
    "Respond ONLY with a JSON object in this exact format: "
    '{"answer_relevancy": <float>, "reason": "<short‑explanation>"}.'
)
_ANSWER_CORRECTNESS_PROMPT = (
    "Score the ANSWER CORRECTNESS: does the generated Answer correctly answer the Question and match the ground‑truth? "
    "Respond ONLY with a JSON object in this exact format: "
    '{"answer_correctness": <float>, "reason": "<short‑explanation>"}.'
)
_CONTEXT_RECALL_PROMPT = (
    "How much of the ground‑truth information is *recalled* in the Context? "
    "Respond ONLY with a JSON object in this exact format: "
    '{"context_recall": <float>, "reason": "<short‑explanation>"}.'
)
_CONTEXT_PRECISION_PROMPT = (
    "How precise is the Context (i.e., does it contain only relevant information for the Answer)? "
    "Respond ONLY with a JSON object in this exact format: "
    '{"context_precision": <float>, "reason": "<short‑explanation>"}.'
)
def build_evaluation_prompt(item: dict) -> str:
    """
    Build the full prompt for a single QA item.
    The prompt contains:
      * Question
      * Answer (generated by your RAG pipeline)
      * Retrieved contexts (concatenated)
      * Ground‑truth (if present)
      * Five metric questions (separated by a blank line)
    """
    q = item["question"]
    a = item["answer"]
    ctx = "\n---\n".join(item["contexts"])
    gt = item.get("ground_truth", "")
    header = (
        f"Question:\n{q}\n\n"
        f"Answer (generated by the system):\n{a}\n\n"
        f"Retrieved contexts (each block separated by a line):\n{ctx}\n\n"
        f"Ground‑truth (if available):\n{gt}\n"
        "---\n"
    )
    metric_block = "\n\n".join(
        [_FAITHFULNESS_PROMPT, _ANSWER_RELEVANCY_PROMPT, _ANSWER_CORRECTNESS_PROMPT,
         _CONTEXT_RECALL_PROMPT, _CONTEXT_PRECISION_PROMPT]
    )
    return header + metric_block
# ----------------------------------------------------------------------
# ── Clean Groq response (strip loop‑detection tag)
# ----------------------------------------------------------------------
def clean_groq_response(text: str) -> str:
    """Remove the safety‑tag that Groq may prepend."""
    return text.replace("[ignoring loop detection]", "").strip()
# ----------------------------------------------------------------------
# ── Evaluate a single item
# ----------------------------------------------------------------------
def evaluate_item(item: dict, model: str) -> dict:
    """
    Send the prompt for one item to Groq, parse the JSON result,
    compute the weighted overall score and return a dict with all scores.
    """
    prompt = build_evaluation_prompt(item)
    for attempt in range(1, _MAX_RETRIES + 1):
        try:
            resp = client.chat.completions.create(
                model=model,
                messages=[{"role": "user", "content": prompt}],
                max_tokens=512,
                temperature=0,
            )
            raw = resp.choices[0].message.content
            cleaned = clean_groq_response(raw)
            # Parse the JSON result containing five metric keys
            try:
                # Try parsing the response as a single JSON object containing all metrics
                scores = json.loads(cleaned)
            except json.JSONDecodeError:
                # Fallback: extract individual JSON objects from the text and merge them
                import re
                matches = re.findall(r"\{[^}]*\}", cleaned)
                scores = {}
                for m in matches:
                    try:
                        part = json.loads(m)
                        scores.update(part)
                    except json.JSONDecodeError:
                        continue
                if not scores:
                    raise
            # Compute overall as the average of the five metrics
            overall = (
                scores["faithfulness"] +
                scores["answer_relevancy"] +
                scores["answer_correctness"] +
                scores["context_recall"] +
                scores["context_precision"]
            ) / 5.0
            scores["overall"] = round(overall, 4)
            # Round each metric for readability
            for k in ["faithfulness", "answer_relevancy", "answer_correctness",
                      "context_recall", "context_precision"]:
                scores[k] = round(scores[k], 4)
            # ----------------------------------------------------------
            # Smart override for "info genuinely absent" cases.
            #
            # ONLY boost when BOTH conditions are true:
            #   (a) The LLM answer says it could not find the info
            #   (b) The ground-truth CONFIRMS the info is absent
            #
            # If GT has real info but LLM says "could not find" →
            #   that's a retrieval failure, keep the low score.
            # ----------------------------------------------------------
            _NO_INFO_ANSWER = [
                "could not find", "unable to find", "not found in",
                "no information", "not available in", "i don't have",
                "cannot find", "not mentioned", "couldn't find",
            ]
            _NO_INFO_GT = [
                "does not provide", "does not list", "does not describe",
                "does not specify", "does not mention", "does not contain",
                "does not state", "does not include",
                "not a supported", "no specific", "not live chat",
                "document does not", "guide does not",
            ]
            answer_lower = item.get("answer", "").lower()
            gt_lower = item.get("ground_truth", "").lower()
            answer_says_no_info = any(p in answer_lower for p in _NO_INFO_ANSWER)
            gt_confirms_absent = any(p in gt_lower for p in _NO_INFO_GT)

            if answer_says_no_info and gt_confirms_absent:
                for k in ["faithfulness", "answer_relevancy", "answer_correctness",
                          "context_recall", "context_precision"]:
                    scores[k] = 1.0
                scores["overall"] = 1.0
            return scores
        except json.JSONDecodeError:
            print(f"[!] JSON decode failed (attempt {attempt}/{_MAX_RETRIES}) – retrying.")
        except Exception as e:
            err = str(e).lower()
            if ("429" in err or "rate limit" in err) and attempt < _MAX_RETRIES:
                wait = _RATE_LIMIT_WAIT * attempt
                print(f"[!] Rate‑limit hit – waiting {wait}s before retry.")
                time.sleep(wait)
            else:
                raise RuntimeError(f"Groq evaluation failed: {e}")
    raise RuntimeError("Maximum retries exceeded for this item.")
# ----------------------------------------------------------------------
# ── Main driver – iterate over phases, checkpoint to a *new* file
# ----------------------------------------------------------------------
def run_evaluation():
    model = pick_working_model()
    for phase_idx, phase in enumerate(PHASES):
        # ------------------------------------------------------------------
        #   Load original progress file (generated by the RAG pipeline)
        # ------------------------------------------------------------------
        source_file = f"phase_progress_{phase}.json"
        if not os.path.exists(source_file):
            print(f"[SKIP] {phase} – source file not found.")
            continue
        # ------------------------------------------------------------------
        #   Determine the evaluated‑output file name
        # ------------------------------------------------------------------
        eval_file = f"phase_progress_{phase}_evaluated.json"
        # Load the original data (never mutated)
        with open(source_file, "r", encoding="utf-8") as f:
            original_results = json.load(f)
        # Load existing evaluated results if we have a checkpoint; otherwise start fresh
        if os.path.exists(eval_file):
            with open(eval_file, "r", encoding="utf-8") as f:
                evaluated_results = json.load(f)
            print(f"[RESUME] Loaded existing checkpoint ({eval_file}).")
        else:
            evaluated_results = []  # will be populated as we go
            print(f"[START] New evaluation for phase '{phase}'.")
        # Build a quick lookup: map question_number → result dict in evaluated_results
        eval_lookup = {
            itm.get("question_number"): itm
            for itm in evaluated_results
        }
        # ------------------------------------------------------------------
        #   Process each item from the *source* list
        # ------------------------------------------------------------------
        pending = [
            itm for itm in original_results
            if itm.get("status") == "success"
            and itm.get("answer", "").strip()
            and itm.get("question_number") not in eval_lookup
        ]
        total = len(pending)
        if total == 0:
            print("[INFO] No pending items for this phase.")
            # Still write out the (already‑complete) checkpoint so later steps can find it
            with open(eval_file, "w", encoding="utf-8") as f:
                json.dump(evaluated_results, f, indent=2, ensure_ascii=False)
            continue
        print(f"[INFO] {total} items need scoring (out of {len(original_results)} total).")
        for idx, src_item in enumerate(pending, start=1):
            print(f"  [{idx}/{total}] Q#{src_item['question_number']}: {src_item['question'][:70]}…")
            try:
                scores = evaluate_item(src_item, model)
                # Attach scores & metadata
                src_item["scores"] = scores
                src_item["judge_model"] = f"groq/{model}"
                src_item.pop("scores_pending", None)
                # Append to the evaluated list (checkpoint)
                evaluated_results.append(src_item)
                # Write checkpoint after each item
                with open(eval_file, "w", encoding="utf-8") as f:
                    json.dump(evaluated_results, f, indent=2, ensure_ascii=False)
                # Console one‑line summary
                f"      overall={scores['overall']:.3f}  "
                f"faith={scores['faithfulness']:.2f}  "
                f"rel={scores['answer_relevancy']:.2f}  "
                f"corr={scores['answer_correctness']:.2f}  "
                f"recall={scores['context_recall']:.2f}  "
                f"prec={scores['context_precision']:.2f}"

            except Exception as e:
                print(f"      ✗ Error on this item: {e}")
            # Pause between items to avoid Groq rate limits
            time.sleep(20)
        # ------------------------------------------------------------------
        #   Phase‑level aggregation & final output file
        # ------------------------------------------------------------------
        total_time = sum(item.get("response_time", 0.0) for item in original_results)
        summary = summarize_results(phase, evaluated_results, len(original_results), total_time)
        payload = {
            "phase": phase,
            "generated_at": datetime.now().isoformat(),
            "judge": f"groq/{model}",
            "eval_method": "direct (faithfulness, answer_relevancy, answer_correctness, context_recall, context_precision)",
            "summary": summary,
            "results": evaluated_results,
        }
        write_outputs(phase, payload)
        # Small wait before the next phase
        if phase_idx < len(PHASES) - 1:
            print("\nWaiting 15 s before the next phase...")
            time.sleep(15)
    print("\n[DONE] All phases complete.")
if __name__ == "__main__":
    run_evaluation()